@import"https://fontsapi.zeoseven.com/629/main/result.css";@import"https://fontsapi.zeoseven.com/701/main/result.css";.thoughts-card{position:relative;width:100%;height:300px;margin:12px auto}@media(min-width: 480px){.thoughts-card{width:80%}}.thoughts-card{border-radius:14px;overflow:hidden;background:linear-gradient(135deg, #fff0f3 0%, #fde8ee 60%, #fad4e0 100%);border:1px solid #f4b8cc;box-shadow:0 2px 10px rgba(220,100,130,.15),inset 0 1px 0 hsla(0,0%,100%,.8)}.envelope-cover{position:absolute;top:0;left:0;width:100%;height:100%;z-index:2;display:flex;flex-direction:column;background:linear-gradient(160deg, #fce4ec 0%, #f8bbd0 40%, #f48fb1 100%);border-bottom:2px solid #e8a0bc;filter:drop-shadow(0 6px 12px rgba(180, 60, 100, 0.32)) drop-shadow(0 2px 4px rgba(180, 60, 100, 0.2));cursor:pointer;transform:translateY(0);transition:transform .45s cubic-bezier(0.4, 0, 0.2, 1);will-change:transform}.envelope-cover.is-revealed{transform:translateY(calc(-100% + 2em))}.envelope-cover::before{content:"";position:absolute;inset:0;pointer-events:none;z-index:0;mix-blend-mode:overlay;background:repeating-linear-gradient(135deg, rgba(255, 255, 255, 0.1) 0px, rgba(255, 255, 255, 0.1) 1px, transparent 1px, transparent 0.75em)}.cover-body{flex:1;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;padding:16px 28px;pointer-events:none;overflow:hidden}.petal{position:absolute;color:#c0506a;pointer-events:none;display:block}.petal svg{display:block;width:100%;height:100%}.petal-1{width:42px;height:42px;top:-8px;left:-10px;opacity:.22;transform:rotate(-20deg)}.petal-2{width:28px;height:28px;top:10px;right:8px;opacity:.26;transform:rotate(15deg)}.petal-3{width:20px;height:20px;top:38px;left:22px;opacity:.18;transform:rotate(8deg)}.petal-4{width:50px;height:50px;bottom:-14px;right:-12px;opacity:.2;transform:rotate(30deg)}.petal-5{width:22px;height:22px;bottom:18px;left:14px;opacity:.22;transform:rotate(-12deg)}.petal-6{width:16px;height:16px;top:50%;left:6px;opacity:.15;transform:translateY(-50%) rotate(5deg)}.petal-7{width:32px;height:32px;bottom:10px;right:28px;opacity:.17;transform:rotate(-25deg)}.vline{position:absolute;top:14px;bottom:14px;width:1px}.vline-left{left:14px;background:linear-gradient(to bottom, transparent, rgba(180, 80, 110, 0.3) 30%, rgba(180, 80, 110, 0.3) 70%, transparent)}.vline-right{right:14px;background:linear-gradient(to bottom, transparent, rgba(180, 80, 110, 0.3) 30%, rgba(180, 80, 110, 0.3) 70%, transparent)}.cover-title{display:flex;align-items:baseline;gap:6px;font-family:"NaikaiFont",serif;font-weight:400;font-size:1.3em;letter-spacing:.12em;line-height:1.5;position:relative;z-index:1}.cover-name{color:#7a1030}.cover-divider{color:rgba(180,80,110,.5);font-size:.85em}.cover-suffix{color:#b85070}.cover-seal{position:absolute;width:33.33%;aspect-ratio:1;bottom:-8.33%;right:-8.33%;border:2px solid rgba(160,50,80,.35);border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:"NaikaiFont",serif;container-type:size;pointer-events:none;z-index:1}.seal-text{font-size:50cqmin;color:rgba(140,40,70,.38);line-height:1}.cover-footer{flex-shrink:0;height:2em;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:rgba(240,160,185,.55);border-top:1px solid rgba(200,100,140,.3);cursor:pointer;pointer-events:auto}.envelope-cover:not(.is-revealed) .cover-footer{pointer-events:none}.footer-title{font-size:.78em;font-weight:400;letter-spacing:.04em;font-family:"NaikaiFont",serif;opacity:0;transition:opacity .3s ease}.footer-title.is-visible{opacity:1}.footer-name{color:#8b1a3a}.footer-suffix{color:#a04060}.cover-icon{font-size:.82em;color:rgba(120,40,70,.65);transition:color .2s}.cover-footer:hover .cover-icon{color:rgba(120,40,70,.9)}.letter-body{position:absolute;inset:0;padding-top:2em;overflow-y:auto;scrollbar-width:thin;scrollbar-color:#f0a0be rgba(0,0,0,0)}.letter-body::-webkit-scrollbar{width:4px}.letter-body::-webkit-scrollbar-thumb{background:#f0a0be;border-radius:2px}.letter-content{padding:14px 20px 22px 26px;color:#7a2a48;font-size:.82em;line-height:2;white-space:pre-wrap;font-family:"MaokenYingBiKaiShuJ",serif;position:relative;background-image:repeating-linear-gradient(to bottom, transparent 0px, transparent 25px, rgba(220, 140, 170, 0.3) 25px, rgba(220, 140, 170, 0.3) 26px);background-position:0 14px;background-size:100% 26px}.letter-content::before{content:"";position:absolute;left:12px;top:14px;bottom:14px;width:2px;background:linear-gradient(to bottom, transparent, #f4b8cc 20%, #e8a0bc 80%, transparent);border-radius:1px;pointer-events:none}